import json, os, httpx

url = os.environ.get('SUPABASE_URL', '') + '/rest/v1/sai_memory'
key = os.environ.get('SUPABASE_ANON_KEY', '') or os.environ.get('SUPABASE_KEY', '')
headers = {
    'apikey': key,
    'Authorization': f'Bearer {key}',
    'Content-Type': 'application/json'
}
# Get schema info - just grab one row
params = {'category': 'eq.position_mastery', 'select': '*', 'limit': '3'}
r = httpx.get(url, headers=headers, params=params)
if r.status_code == 200:
    data = r.json()
    print(f'Found {len(data)} rows')
    for d in data:
        print(json.dumps(d, indent=2, default=str))
else:
    print(f'Error {r.status_code}: {r.text}')

# Also get any row to see columns
params2 = {'select': '*', 'limit': '1'}
r2 = httpx.get(url, headers=headers, params=params2)
if r2.status_code == 200:
    data2 = r2.json()
    if data2:
        print('\\nColumns:', list(data2[0].keys()))
" 2>&1

