import json, os, httpx

url = os.environ.get('SUPABASE_URL', '') + '/rest/v1/sai_memory'
key = os.environ.get('SUPABASE_ANON_KEY', '') or os.environ.get('SUPABASE_KEY', '')
headers = {
    'apikey': key,
    'Authorization': f'Bearer {key}',
    'Content-Type': 'application/json'
}
params = {'category': 'eq.position_mastery', 'select': 'content'}
r = httpx.get(url, headers=headers, params=params)
if r.status_code == 200:
    data = r.json()
    print(f'Total position_mastery rows: {len(data)}')
    for d in data:
        c = json.loads(d['content']) if isinstance(d['content'], str) else d['content']
        print(f'  {c.get(\"cluster_family\",\"?\")} > {c.get(\"cluster_name\",\"?\")} > {c.get(\"position_name\",\"?\")}')
else:
    print(f'Error {r.status_code}: {r.text}')
" 2>&1
